    try riskyOperation()
} catch {
    // Error swallowed
}
```

**Fix**: Handle errors explicitly:
```swift
do {
    let data = try Data(contentsOf: url)
} catch let error as NSError where error.code == NSFileNoSuchFileError {
    // Handle file not found
} catch {
    // Handle other errors
}
```

